import{_ as t,o as a,c as r,a2 as o}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 33 — Search History","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/33-search-history.md","filePath":"chapters/33-search-history.md"}'),h={name:"chapters/33-search-history.md"};function s(c,e,i,d,n,l){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="chapter-33-—-search-history" tabindex="-1">Chapter 33 — Search History <a class="header-anchor" href="#chapter-33-—-search-history" aria-label="Permalink to &quot;Chapter 33 — Search History&quot;">​</a></h1><blockquote><p><em>&quot;Every search is remembered. Reuse them effortlessly.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐ Beginner-Intermediate <strong>Estimated Reading Time:</strong> 10 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Vim remembers all your searches during a session.</p><hr><h1 id="navigating-search-history" tabindex="-1">Navigating Search History <a class="header-anchor" href="#navigating-search-history" aria-label="Permalink to &quot;Navigating Search History&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>/</code> then <code>↑</code></td><td>Previous search</td></tr><tr><td><code>/</code> then <code>↓</code></td><td>Next search</td></tr><tr><td><code>?</code> then <code>↑</code></td><td>Previous backward search</td></tr><tr><td><code>?</code> then <code>↓</code></td><td>Next backward search</td></tr></tbody></table><h2 id="clearing-search" tabindex="-1">Clearing Search <a class="header-anchor" href="#clearing-search" aria-label="Permalink to &quot;Clearing Search&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:noh</code></td><td>Remove search highlighting</td></tr><tr><td><code>:let @/ = &quot;&quot;</code></td><td>Clear search register</td></tr></tbody></table><hr><h1 id="search-register" tabindex="-1">Search Register <a class="header-anchor" href="#search-register" aria-label="Permalink to &quot;Search Register&quot;">​</a></h1><p>The last search pattern is stored in the <code>/</code> register.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:echo @/</span></span></code></pre></div><p>Shows the last search pattern.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:let @/ = &quot;foo&quot;</span></span></code></pre></div><p>Sets the search pattern to <code>foo</code>.</p><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><code>↑</code>/<code>↓</code> after <code>/</code> or <code>?</code> browses history.</li><li><code>:noh</code> clears highlighting.</li><li><code>@/</code> register stores the last search.</li></ul><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./34-replace.html"><strong>Chapter 34 — Replace</strong></a></p><p>Advanced replacement techniques with patterns.</p>',26)])])}const g=t(h,[["render",s]]);export{u as __pageData,g as default};
